package main

import (
	"crypto/hmac"
	"crypto/sha256"
)

func verify(sig, expected []byte, key []byte) bool {
	mac := hmac.New(sha256.New, key)
	mac.Write(expected)
	computed := mac.Sum(nil)
	return hmac.Equal(sig, computed)
}

