pub fn average(xs: &[i32]) -> Option<i64> {
    if xs.is_empty() { return None; }
    let sum: i64 = xs.iter().map(|&x| x as i64).sum();
    Some(sum / xs.len() as i64)
}

pub fn last<T: Clone>(v: &[T]) -> Option<T> {
    v.last().cloned()
}
